head.script:
scwin.strCurDate = $c.date.getServerDateTime();
scwin.strPreDate = $c.date.getDateAddMonthDirection(scwin.strCurDate, 0 , "F");
scwin.strLastDay = $c.date.getDateAddMonthDirection(scwin.strCurDate, 0 , "L");

scwin.userId = $c.data.getMemInfo("userId");
scwin.userClsCd = $c.data.getMemInfo("userClsCd");
scwin.loginClntNo = "";
scwin.loginClntNm = $c.data.getMemInfo("clntNm");

scwin.p_hhio = "";

scwin.curRow = ""; 
scwin.hid_checkHouseBl = "";    
scwin.hd_kcomcd = "DBEX";

scwin.onpageload = function () {
    scwin.loginClntNo = $c.data.getMemInfo("clntNo") == null ? "" : $c.data.getMemInfo("clntNo");
    scwin.p_hhio = $c.data.getParameter("hhio") == null ? "" : $c.data.getParameter("repChhiolntNo");

    // 공통코드 설정
    codeOptions = [ 
        { grpCd : "IL080", compID : "gr_master:triItemType"},
    ];
    $c.data.setCommonCode(codeOptions);

    scwin.f_setDSHeader();
};

scwin.onUdcCompleted = function () {
    scwin.f_set("ONLOAD");
};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
scwin.f_setDSHeader = function () {
    ds_retrieve.insertRow();  
    ds_retrieve.setRowPosition(0);

    ds_retrieve2.insertRow();  
    ds_retrieve2.setRowPosition(0);

    ds_cntrInfo.insertRow();  
    ds_cntrInfo.setRowPosition(0);

    ds_wgtInfo.insertRow();  
    ds_wgtInfo.setRowPosition(0);
};

// 화면 open시 초기 데이타 setting
scwin.f_set = function (gubun) {
    switch (gubun) {
        case "ONLOAD":      
            $c.gus.cfDisableKey();
            ed_etdEtaSt.setValue(scwin.strPreDate);
            ed_etdEtaEnd.setValue(scwin.strLastDay);
            // 테스트데이터
            // ed_etdEtaSt.setValue("20250301");
            // ed_etdEtaEnd.setValue("20250301");
            // lc_etdEta.setSelectedIndex(0);
            // cbx_complYn.setValue("");
        break;

        case "RETRIEVE":
            $c.gus.cfEnableAllBtn();
        break; 	

        case "DELETE":
            $c.gus.cfDisableBtn();
        break;    	
    }
};

// 조회
scwin.f_Retrieve = async function () {
    // VALIDATE
    if (!await $c.gus.cfValidate([lc_etdEta, lc_docCargo])) {  //validExp 가 yes일때 check
        return;
    }	

    // 날짜 범위 확인
    if (ed_etdEtaSt.getValue() != "" || ed_etdEtaEnd.getValue() != "") {
        if (!await $c.gus.cfIsAfterDate(ed_etdEtaSt.getValue(), ed_etdEtaEnd.getValue())) {
            if (await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("ETD From", "ETD To"))) { //@은(는) 보다 작아야 합니다.
                ed_etdEtaSt.focus();
                return false;
            }  
        }
    }	

    // 날짜 범위 확인
    if (ed_docCargoSt.getValue() != "" || ed_docCargoEnd.getValue() != "") {
        if (!await $c.gus.cfIsAfterDate(ed_docCargoSt.getValue(), ed_docCargoEnd.getValue())) {
            if (await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, new Array("DOC From", "DOC To"))) { //@은(는) 보다 작아야 합니다.
                ed_docCargoSt.focus();
                return false;
            }  
        }
    }

    let e = await $c.sbm.execute(sbm_retrieve);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieve_submitdone(e);
    }
};

// 저장
scwin.f_save = async function () {
    if (ds_master.getModifiedIndex().length == 0) { 
        $c.win.alert("변경된 사항이 없습니다."); 
        return;
    }

    for (var i = 0; i < ds_master.getRowCount(); i++) {
        if (ds_master.getModifiedIndex().length != 0 && ds_master.getRowStatus(i) == "U") { 
            if (ds_master.getCellData(i, "issueYn") == "T" && ds_master.getCellData(i, "hhblno")=="") {
                $c.win.alert("ISSUE 체크는 BL 등록후에 가능합니다.");
                return;
            }

            if (ds_master.getCellData(i, "isfYn") == "T" && ds_master.getCellData(i, "hhblno") == "") {
                $c.win.alert("ISF 체크는 BL 등록후에 가능합니다.");
                return;
            }

            if (ds_master.getCellData(i, "prealertYn") == "T" && ds_master.getCellData(i, "hhblno") == "") {
                $c.win.alert("PRE ALERT 체크는 BL 등록후에 가능합니다.");
                return;
            }								
        }
    }

    let saveChk = await $c.win.confirm(MSG_CM_CRM_001);
    if (saveChk) {  
        // RowPosition 저장
        scwin.f_GetRowPosition();
        let e = await $c.sbm.execute(sbm_save);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_save_submitdone(e);
        }   
    }  
}

scwin.f_GetRowPosition = function () {
    scwin.curRow = ds_master.getRowPosition();
}

scwin.f_SetRowPosition = function () {
    scwin.curRow = "";
}

// 조회 조건 지우기
scwin.f_FieldClear = function ()  {
    $c.gus.cfInitObjects(tb_searchCondition, []); // 조회조건의 테이블을 초기화.
    scwin.f_set("ONLOAD"); 
};

// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
scwin.f_PopUp = function (disGubun, chgGubun) {
    var rtnList = new Array();
    switch (disGubun) {
        case "Customer":
            udc_custCd.setSelectId("retrieveEngClntInfo");    
            udc_custCd.ilCommonPopUp(
                                        scwin.udc_custCd_callBackFunc,                                                     							
                                        ed_custCd.getValue().trim(),                                                    // 화면에서의 ??? Code Element의	Value                                  
                                        ed_custNm.getValue(),                                                           // 화면에서의 ??? Name Element의	Value                                  
                                        chgGubun,                                                                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                        '10',                                                                           // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                        'Customer Code,Customer Name,Address1,Address2,Address3,Address4,Tel,,,CRN',    // Title순서	                                                           
                                        '140,300,100,100,100,100,100,,,100',                                            // 보여주는 각 컬럼들의 폭	                                               
                                        '8,9',                                                                          // 컬럼중에서 숨기는	컬럼 지정	                                       
                                        null,                                                                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                        '500',                                                                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                        '500',                                                                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                        null,                                                                           // 윈도우 위치 Y좌표	                                                   
                                        null,                                                                           // 윈도우 위치 X좌표                                                       
                                        null,                                                                           // 중복체크여부	("F")                                                      
                                        "F",                                                                            // 전체검색허용여부	("F")                                                  
                                        'Customer search,Customer Code,Customer Name'
                                    );
        break;	
        case "Liner":  
            ucd_liner.setSelectId("retrieveEngClntInfo"); 
            ucd_liner.ilCommonPopUp(
                                        scwin.ucd_liner_callBackFunc,                                                    							
                                        ed_liner.getValue().trim(),                                             // 화면에서의 ??? Code Element의	Value                                  
                                        ed_linerNm.getValue(),                                                  // 화면에서의 ??? Name Element의	Value                                  
                                        chgGubun,                                                               // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                        '10',                                                                   // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                        'Liner Code,Liner Name,Address1,Address2,Address3,Address4,Tel,,,CRN',  // Title순서	                                                           
                                        '140,300,100,100,100,100,100,,,100',                                    // 보여주는 각 컬럼들의 폭	                                               
                                        '8,9',                                                                  // 컬럼중에서 숨기는	컬럼 지정	                                       
                                        null,                                                                   // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                        '500',                                                                  // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                        '500',                                                                  // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                        null,                                                                   // 윈도우 위치 Y좌표	                                                   
                                        null,                                                                   // 윈도우 위치 X좌표                                                       
                                        null,                                                                   // 중복체크여부	("F")                                                      
                                        "F",                                                                    // 전체검색허용여부	("F")                                                  
                                        'Liner search,Liner Code,Liner Name'
                                    );
        break;	
  	}	
};

