// 엑셀다운로드
scwin.f_downExcelSheet = async function () {
	var cntRow = ds_master.getRowCount();

	if (cntRow > 0) {
		var cfrm = await $c.win.confirm("Sea Export Container Shipment List를 EXCEL로 다운로드 받으시겠습니까?");
		if (cfrm) {
            const options = {
                fileName: "Sea Export Container Shipment" + ".xlsx" // [default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                , sheetName: "Sea Export Container Shipment"
                , type : 1 + 2 + 4 + 8 + 16
            };

            const infoArr = [];

            $c.data.downloadGridViewExcel(gr_master, options, infoArr);
		}
    } else {
		await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002); // 조회결과가 존재하지 않습니다.  
    }
};

// 상세내역 조회
scwin.f_detailSet = async function () {	
    var rnt = "";
    ds_retrieve2.setCellData(0, "bkNo2", ds_master.getCellData(ds_master.getRowPosition(), "bkNo"));

    rnt = await $c.sbm.execute(sbm_retrieveDetail);
