    ed_cfsNm2.setStyle("color", "black"); 
    ed_shrNm2.setStyle("color", "black"); 
    ed_chargeStatus.setStyle("color", "black"); 
    ed_liner2.setStyle("color", "black"); 
    ed_carrierBkNo2.setStyle("color", "black"); 
    ed_vslVoy.setStyle("color", "black"); 
    ed_lodNm2.setStyle("color", "black"); 
    ed_disNm2.setStyle("color", "black"); 
    ed_bkEtd2.setStyle("color", "black"); 
    ed_bkEta2.setStyle("color", "black"); 
    ed_ts1PortNm2.setStyle("color", "black"); 
    ed_ts1VslVoy.setStyle("color", "black"); 
    ed_ts1Etd2.setStyle("color", "black"); 
    ed_ts1Eta2.setStyle("color", "black"); 
    ed_ts2PortNm2.setStyle("color", "black"); 
    ed_ts2VslVoy.setStyle("color", "black"); 
    ed_ts2Etd2.setStyle("color", "black"); 
    ed_ts2Eta2.setStyle("color", "black"); 	
    ed_docClosingDt2.setStyle("color", "black"); 	
    ed_cargoClosingDt2.setStyle("color", "black"); 
    ed_cargoType2.setStyle("color", "black"); 	
    ed_reDt2.setStyle("color", "black"); 		
    ed_cnttype1.setStyle("color", "black"); 
    ed_cnttype2.setStyle("color", "black"); 
    ed_cnttype3.setStyle("color", "black"); 
    ed_cnttype4.setStyle("color", "black"); 	
    ed_wgt.setStyle("color", "black"); 
    ed_pkg.setStyle("color", "black"); 
    ed_payTerm.setStyle("color", "black"); 	
    ed_refNo2.setStyle("color", "black"); 
    ed_freeDay.setStyle("color", "black"); 
    ed_refBuyingAmt.setStyle("color", "black"); 
    ed_refSellingAmt.setStyle("color", "black"); 
    txa_remarkMaster.setStyle("color", "black"); 

    if (ds_master.getCellData( ds_master.getRowPosition(), "iptYn") == "1") {
        ed_custCd2.setStyle("background-color", "yellow"); 
    } else {
        ed_custCd2.setStyle("background-color", "white"); 
    }

    if (ds_master.getCellData( ds_master.getRowPosition(),"custCdSeq") != "" && ds_master.getCellData(ds_master.getRowPosition(), "prgStatus") == "BK") {
        ed_custCd2.setValue(ds_master.getCellData(ds_master.getRowPosition(), "custNm")); 
        ed_custCd2.setStyle("color", "red"); 
    } else if (ds_master.getCellData(ds_master.getRowPosition(),"custCdSeq") != "" && ds_master.getCellData(ds_master.getRowPosition(), "prgStatus") =="BL") {
        ed_custCd2.setValue(ds_master.getCellData(ds_master.getRowPosition(), "custNm")); 
        ed_custCd2.setStyle("color", "blue"); 
    } else {
