        ed_custTeam2.setStyle("color", "red"); 
    } else {
        ed_custTeam2.setValue(ds_master.getCellData(ds_master.getRowPosition(),"custTeam")+" / "+ds_master.getCellData(ds_master.getRowPosition(),"custTeamPic"));	
    }

    if (ds_master.getCellData(ds_master.getRowPosition(),"triYn") == 0) {
        ed_triYn2.setValue("N");
