    ed_chargeStatus.setValue(ds_master.getCellData(ds_master.getRowPosition(),"chargeStatus"));	

    if (ds_master.getCellData( ds_master.getRowPosition(),"linerSeq")!="" && ds_master.getCellData(ds_master.getRowPosition(),"prgStatus") =="BK") {
        ed_liner2.setValue(ds_master.getCellData(ds_master.getRowPosition(),"linernm"));
