        ed_liner2.setStyle("color", "blue"); 
    } else {
        ed_liner2.setValue(ds_master.getCellData(ds_master.getRowPosition(),"linernm"));	
    }

    if (ds_master.getCellData(ds_master.getRowPosition(),"carrierBkNoSeq")!="") {
        ed_carrierBkNo2.setValue(ds_master.getCellData(ds_master.getRowPosition(),"carrierBkNo"))	;
        ed_carrierBkNo2.setStyle("color", "red"); 

    } else {
        ed_carrierBkNo2.setValue(ds_master.getCellData(ds_master.getRowPosition(),"carrierBkNo"))	;
    }	

    if ((ds_master.getCellData( ds_master.getRowPosition(),"vsslNmSeq")!="" || ds_master.getCellData(ds_master.getRowPosition(),"voySeq"!=""))&& ds_master.getCellData(ds_master.getRowPosition(),"prgStatus") =="BK") {
