//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {
	if (ds_master.getRowCount() > 0) {
		var cnt = 0;
		var blNo = ""; 
		for (var i = 0; i < ds_master.getRowCount(); i++) {

			if (blNo != ds_master.getCellData(i, "hhblno")) {
				cnt++;
			} else {
				blNo = ds_master.getCellData(i, "hhblno");	
            }			
		}

		var cnt2 = 0;
		var vBkNo = ""; 

		for (var i = 0; i < ds_master.getRowCount(); i++) {
			if (vBkNo != ds_master.getCellData(i, "bkNo")) {
				cnt2++;
			}			
			vBkNo = ds_master.getCellData(i, "bkNo");		
		}				

        totalRows.setValue(cnt);    // 조회된 건수를 매출입항목Grid 하단에 표시한다.		
        totalRows2.setValue(cnt2);  // 조회된 건수를 매출입항목Grid 하단에 표시한다.				

        let e = await $c.sbm.execute(sbm_retrieveTypeInfo);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieveTypeInfo_submitdone(e);
        }

		scwin.f_setColumn();
	} else {
		if (await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002)) { // 조회결과가 존재하지 않습니다.  
            $c.gus.cfInitObjects(tb_master, []); // 상세내용 테이블을 초기화.
        } 
	}

	// 저장 후 RowPosition
	if (scwin.curRow != "") {
 		ds_master.setRowPosition(scwin.curRow);
		scwin.f_SetRowPosition();
 	}
};

scwin.sbm_retrieveTypeInfo_submitdone = async function (e) {
    var rowCount = ds_cntrInfo.getRowCount();
   	if (rowCount > 0) {
        let typeInfo = "";
	    ed_typeInfo.setValue("");

        for (var i = 0; i < ds_cntrInfo.getRowCount() - 1; i++) { 
            typeInfo += ds_cntrInfo.getCellData(i, "typeInfo") + ": " + ds_cntrInfo.getCellData(i, "qtyInfo") + ", ";
        }
        var lastIdx = rowCount - 1;
        typeInfo += ds_cntrInfo.getCellData(lastIdx, "typeInfo") + ": " + ds_cntrInfo.getCellData(lastIdx, "qtyInfo");

        ed_typeInfo.setValue(typeInfo);
	}

	// 총 중량
	ed_grossWgt.setValue("");
    ed_grossWgt.setValue(gr_master.headercolsum('wgt')); 
};

scwin.sbm_save_submitdone = async function (e) {
    if (await $c.gus.cfAlertMsg(MSG_CM_INF_001)) { // 성공적으로 저장하였습니다
        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        }
    }	
};

scwin.sbm_retrieveDetail_submitdone = async function (e) {
    totalRows_bulk.setValue(ds_detail1.getRowCount()); 
};

scwin.sbm_retrieveDetail2_submitdone = async function (e) {
    totalRows_cntr.setValue(ds_detail2.getRowCount()); 
};

