scwin.gr_master_oncelldblclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex > -1) { 
        var paramObj = {
        }
        let options = {
            "openAction": "exist"
        };
        var menuName = "";
        var menuUrl = "";
        var menuUrlNm = "";

        if (columnId=="bkNo") { 
            paramObj = {
                linkcheck : "1",
                kcomcd : scwin.hd_kcomcd,
                bkno : ds_master.getCellData(rowIndex, "bkNo"),
            }
            menuName = "Container Booking";
            menuUrl = "/ui/il/seaout/sobk/se_101_01_01b.xml";
            menuUrlNm = "se_101_01_01b.jsp";
            $c.win.openMenu(menuName, menuUrl, menuUrlNm, paramObj, options);
        } else if (columnId == "hhblno" && ds_master.getCellData(rowIndex, "autono") == "DIRECT" && ds_master.getCellData(rowIndex,"hhblno")!= "") {
            paramObj = {
                linkcheck : "1",
                kcomcd : scwin.hd_kcomcd,
                blno : ds_master.getCellData(rowIndex, "hhblno"),
                mhno : ds_master.getCellData(rowIndex, "mhno"),
            }
            menuName = "Direct B/L";
            menuUrl = "/ui/il/seaout/sobl/se_107_01_01b.xml";
            menuUrlNm = "se_107_01_01b.jsp";
            $c.win.openMenu(menuName, menuUrl, menuUrlNm, paramObj, options);
        } else if (columnId == "hhblno" && ds_master.getCellData(rowIndex, "autono") != "DIRECT" && ds_master.getCellData(rowIndex, "hhblno") != "") {
            paramObj = {
                linkcheck : "1",
                kcomcd : scwin.hd_kcomcd,
                blno : ds_master.getCellData(rowIndex, "hhblno"),
                mhno : ds_master.getCellData(rowIndex, "mhno"),
            }
            menuName = "Export House B/L";
            menuUrl = "/ui/il/seaout/sobl/se_105_01_01b.xml";
            menuUrlNm = "se_105_01_01b.jsp";
            $c.win.openMenu(menuName, menuUrl, menuUrlNm, paramObj, options);
        }
    }
};

scwin.gr_master_oncellclick = function (rowIndex, columnIndex, columnId) {
    // 바로 체크되도록 
    if (columnId == "epnYn") {
        if (ds_master.getCellData(ds_master.getRowPosition() ,"triYn") != "1") {
            if (ds_master.getCellData(ds_master.getRowPosition() ,"inpid") == scwin.userId || ds_master.getCellData(ds_master.getRowPosition(), "docPic") == scwin.userId || ds_master.getCellData(ds_master.getRowPosition(), "bkPic") == scwin.userId) {
