            } else {
                ds_master.setCellData(ds_master.getRowPosition(), "prealertYn", 'T');
            }
        }
    }
    if (columnId == "issueYn") {
        if (ds_master.getCellData(ds_master.getRowPosition(), "inpid") == scwin.userId || ds_master.getCellData(ds_master.getRowPosition(), "docPic") == scwin.userId || ds_master.getCellData(ds_master.getRowPosition(), "bkPic") == scwin.userId) {
