                bgColor = "white";
            }
        }
    }
    // 1. 모든 컬럼 개수 가져오기
    var colCount = gr_master.getColumnCount(); 

    // 2. 루프를 돌며 모든 셀에 배경색 적용
    for (var i = 0; i < colCount; i++) {
        var colId = gr_master.getColumnID(i); // 인덱스로 컬럼 ID 추출

        // 특정 체크박스 컬럼들을 포함하여 모든 컬럼에 동일한 bgColor 적용
        gr_master.setCellBackgroundColor(rowIndex, colId, bgColor);
    }
    return val;
