    let val = data, color = "black";

    var doorDtSeq = ds_detail1.getCellData(rowIndex, "doorDtSeq");
    var realQtytypeSeq = ds_detail1.getCellData(rowIndex, "realQtytypeSeq");
    var qtySeq = ds_detail1.getCellData(rowIndex, "realQtytypeSeq");
    var vehclQtySeq = ds_detail1.getCellData(rowIndex, "vehclQtySeq");

